package agent

import (
	"context"
	"fmt"

	"google.golang.org/adk/tool"
	"google.golang.org/adk/tool/functiontool"

	"github.com/sentioxyz/changelogue/internal/models"
)

// AgentDataStore defines the data access methods that agent tools use to
// research releases and context sources for a given project.
type AgentDataStore interface {
	ListReleasesByProject(ctx context.Context, projectID string, page, perPage int) ([]models.Release, int, error)
	GetRelease(ctx context.Context, id string) (*models.Release, error)
	ListContextSources(ctx context.Context, projectID string, page, perPage int) ([]models.ContextSource, int, error)
}

// --- Tool input/output types ---

// GetReleasesInput is the input for the get_releases tool.
type GetReleasesInput struct {
	Page    int `json:"page,omitempty"`
	PerPage int `json:"per_page,omitempty"`
}

// ReleaseItem is a single release in the tool output.
type ReleaseItem struct {
	ID         string `json:"id"`
	SourceID   string `json:"source_id"`
	Version    string `json:"version"`
	RawData    any    `json:"raw_data,omitempty"`
	ReleasedAt string `json:"released_at,omitempty"`
	CreatedAt  string `json:"created_at"`
}

// GetReleasesOutput is the output for the get_releases tool.
type GetReleasesOutput struct {
	Releases []ReleaseItem `json:"releases"`
	Total    int           `json:"total"`
	Page     int           `json:"page"`
	PerPage  int           `json:"per_page"`
}

// GetReleaseDetailInput is the input for the get_release_detail tool.
type GetReleaseDetailInput struct {
	ReleaseID string `json:"release_id"`
}

// GetReleaseDetailOutput is the output for the get_release_detail tool.
type GetReleaseDetailOutput struct {
	ID         string `json:"id"`
	SourceID   string `json:"source_id"`
	Version    string `json:"version"`
	RawData    any    `json:"raw_data,omitempty"`
	ReleasedAt string `json:"released_at,omitempty"`
	CreatedAt  string `json:"created_at"`
}

// ListContextSourcesInput is the input for the list_context_sources tool.
type ListContextSourcesInput struct {
	Page    int `json:"page,omitempty"`
	PerPage int `json:"per_page,omitempty"`
}

// ContextSourceItem is a single context source in the tool output.
type ContextSourceItem struct {
	ID     string `json:"id"`
	Type   string `json:"type"`
	Name   string `json:"name"`
	Config any    `json:"config"`
}

// ListContextSourcesOutput is the output for the list_context_sources tool.
type ListContextSourcesOutput struct {
	Sources []ContextSourceItem `json:"sources"`
	Total   int                 `json:"total"`
	Page    int                 `json:"page"`
	PerPage int                 `json:"per_page"`
}

// toolFactory holds the store reference and project ID scoped to a single
// agent run. Tools created from this factory are bound to a specific project.
type toolFactory struct {
	store     AgentDataStore
	projectID string
}

// NewTools creates the ADK function tools for agent research, scoped to a
// specific project. The returned tools use the provided store to query
// releases and context sources belonging to projectID.
func NewTools(store AgentDataStore, projectID string) ([]tool.Tool, error) {
	f := &toolFactory{store: store, projectID: projectID}

	getReleases, err := functiontool.New(functiontool.Config{
		Name:        "get_releases",
		Description: "Fetch recent releases for the current project. Returns a paginated list of releases with version, raw data, and timestamps. Use this to understand what new versions have been published.",
	}, f.getReleases)
	if err != nil {
		return nil, fmt.Errorf("create get_releases tool: %w", err)
	}

	getReleaseDetail, err := functiontool.New(functiontool.Config{
		Name:        "get_release_detail",
		Description: "Get detailed information for a specific release by its ID. Returns the full raw data payload from the upstream provider. Use this to inspect changelogs, commit lists, or other release metadata.",
	}, f.getReleaseDetail)
	if err != nil {
		return nil, fmt.Errorf("create get_release_detail tool: %w", err)
	}

	listContextSources, err := functiontool.New(functiontool.Config{
		Name:        "list_context_sources",
		Description: "List the context sources configured for this project. Context sources are references to runbooks, documentation, monitoring dashboards, and other background materials that help you produce richer analysis.",
	}, f.listContextSources)
	if err != nil {
		return nil, fmt.Errorf("create list_context_sources tool: %w", err)
	}

	return []tool.Tool{getReleases, getReleaseDetail, listContextSources}, nil
}

// getReleases is the handler for the get_releases tool.
func (f *toolFactory) getReleases(ctx tool.Context, input GetReleasesInput) (GetReleasesOutput, error) {
	page := input.Page
	if page < 1 {
		page = 1
	}
	perPage := input.PerPage
	if perPage < 1 || perPage > 50 {
		perPage = 20
	}

	releases, total, err := f.store.ListReleasesByProject(ctx, f.projectID, page, perPage)
	if err != nil {
		return GetReleasesOutput{}, fmt.Errorf("list releases: %w", err)
	}

	items := make([]ReleaseItem, 0, len(releases))
	for _, r := range releases {
		item := ReleaseItem{
			ID:        r.ID,
			SourceID:  r.SourceID,
			Version:   r.Version,
			RawData:   r.RawData,
			CreatedAt: r.CreatedAt.Format("2006-01-02T15:04:05Z"),
		}
		if r.ReleasedAt != nil {
			item.ReleasedAt = r.ReleasedAt.Format("2006-01-02T15:04:05Z")
		}
		items = append(items, item)
	}

	return GetReleasesOutput{
		Releases: items,
		Total:    total,
		Page:     page,
		PerPage:  perPage,
	}, nil
}

// getReleaseDetail is the handler for the get_release_detail tool.
func (f *toolFactory) getReleaseDetail(ctx tool.Context, input GetReleaseDetailInput) (GetReleaseDetailOutput, error) {
	if input.ReleaseID == "" {
		return GetReleaseDetailOutput{}, fmt.Errorf("release_id is required")
	}

	release, err := f.store.GetRelease(ctx, input.ReleaseID)
	if err != nil {
		return GetReleaseDetailOutput{}, fmt.Errorf("get release: %w", err)
	}

	out := GetReleaseDetailOutput{
		ID:        release.ID,
		SourceID:  release.SourceID,
		Version:   release.Version,
		RawData:   release.RawData,
		CreatedAt: release.CreatedAt.Format("2006-01-02T15:04:05Z"),
	}
	if release.ReleasedAt != nil {
		out.ReleasedAt = release.ReleasedAt.Format("2006-01-02T15:04:05Z")
	}

	return out, nil
}

// listContextSources is the handler for the list_context_sources tool.
func (f *toolFactory) listContextSources(ctx tool.Context, input ListContextSourcesInput) (ListContextSourcesOutput, error) {
	page := input.Page
	if page < 1 {
		page = 1
	}
	perPage := input.PerPage
	if perPage < 1 || perPage > 50 {
		perPage = 20
	}

	sources, total, err := f.store.ListContextSources(ctx, f.projectID, page, perPage)
	if err != nil {
		return ListContextSourcesOutput{}, fmt.Errorf("list context sources: %w", err)
	}

	items := make([]ContextSourceItem, 0, len(sources))
	for _, s := range sources {
		items = append(items, ContextSourceItem{
			ID:     s.ID,
			Type:   s.Type,
			Name:   s.Name,
			Config: s.Config,
		})
	}

	return ListContextSourcesOutput{
		Sources: items,
		Total:   total,
		Page:    page,
		PerPage: perPage,
	}, nil
}

package agent

import (
	"context"
	"fmt"
	"log/slog"

	"github.com/riverqueue/river"
	"github.com/sentioxyz/changelogue/internal/queue"
)

// AgentWorker is a River worker that processes AgentJobArgs by running the
// LLM agent orchestrator. When a job is dequeued, it loads the corresponding
// agent run from the store and delegates to Orchestrator.RunAgent.
type AgentWorker struct {
	river.WorkerDefaults[queue.AgentJobArgs]
	orchestrator *Orchestrator
	store        OrchestratorStore
}

// NewAgentWorker creates a new AgentWorker backed by the given orchestrator
// and store.
func NewAgentWorker(orchestrator *Orchestrator, store OrchestratorStore) *AgentWorker {
	return &AgentWorker{
		orchestrator: orchestrator,
		store:        store,
	}
}

// Work processes a single AgentJobArgs job. It loads the agent run from the
// database and runs the LLM agent through the orchestrator.
func (w *AgentWorker) Work(ctx context.Context, job *river.Job[queue.AgentJobArgs]) error {
	slog.Info("agent worker picked up job",
		"job_id", job.ID,
		"agent_run_id", job.Args.AgentRunID,
		"attempt", job.Attempt,
	)

	run, err := w.store.GetAgentRun(ctx, job.Args.AgentRunID)
	if err != nil {
		slog.Error("agent worker failed to load agent run",
			"job_id", job.ID,
			"agent_run_id", job.Args.AgentRunID,
			"err", err,
		)
		return fmt.Errorf("get agent run: %w", err)
	}

	slog.Info("agent worker starting run",
		"job_id", job.ID,
		"agent_run_id", run.ID,
		"project_id", run.ProjectID,
		"trigger", run.Trigger,
	)

	if err := w.orchestrator.RunAgent(ctx, run); err != nil {
		slog.Error("agent worker run failed",
			"job_id", job.ID,
			"agent_run_id", run.ID,
			"project_id", run.ProjectID,
			"err", err,
		)
		return err
	}

	slog.Info("agent worker run completed",
		"job_id", job.ID,
		"agent_run_id", run.ID,
		"project_id", run.ProjectID,
	)
	return nil
}

package queue

import "github.com/riverqueue/river"

// NotifyJobArgs is enqueued when a new source release is detected.
// The worker sends notifications to source-level subscribers.
type NotifyJobArgs struct {
	ReleaseID string `json:"release_id"`
	SourceID  string `json:"source_id"`
}

func (NotifyJobArgs) Kind() string { return "notify_release" }

var _ river.JobArgs = NotifyJobArgs{}

// AgentJobArgs is enqueued when an agent run is triggered.
// The worker runs the LLM agent to produce a semantic release.
type AgentJobArgs struct {
	AgentRunID string `json:"agent_run_id"`
	ProjectID  string `json:"project_id"`
}

func (AgentJobArgs) Kind() string { return "agent_run" }

var _ river.JobArgs = AgentJobArgs{}

package routing

import (
	"context"
	"encoding/json"
	"fmt"
	"log/slog"
	"net/http"
	"time"

	"github.com/riverqueue/river"
	"github.com/sentioxyz/changelogue/internal/models"
	"github.com/sentioxyz/changelogue/internal/queue"
)

// NotifyStore is the data access interface required by the notification worker.
type NotifyStore interface {
	GetRelease(ctx context.Context, id string) (*models.Release, error)
	GetSource(ctx context.Context, id string) (*models.Source, error)
	ListSourceSubscriptions(ctx context.Context, sourceID string) ([]models.Subscription, error)
	GetChannel(ctx context.Context, id string) (*models.NotificationChannel, error)
	GetProject(ctx context.Context, id string) (*models.Project, error)
	GetPreviousRelease(ctx context.Context, sourceID string, beforeVersion string) (*models.Release, error)
	EnqueueAgentRun(ctx context.Context, projectID, trigger string) error
}

// NotifyWorker is a River worker that processes NotifyJobArgs.
// It looks up the release, finds all source-level subscriptions, resolves
// the notification channel for each, and dispatches via the appropriate sender.
// After sending notifications, it checks the project's agent rules and
// auto-triggers an agent run if the version criteria are met.
type NotifyWorker struct {
	river.WorkerDefaults[queue.NotifyJobArgs]
	store   NotifyStore
	senders map[string]Sender
}

// NewNotifyWorker creates a NotifyWorker with default senders for webhook, Slack, and Discord.
func NewNotifyWorker(store NotifyStore) *NotifyWorker {
	return &NotifyWorker{
		store: store,
		senders: map[string]Sender{
			"webhook": &WebhookSender{Client: &http.Client{Timeout: 10 * time.Second}},
			"slack":   &SlackSender{Client: &http.Client{Timeout: 10 * time.Second}},
			"discord": &DiscordSender{Client: &http.Client{Timeout: 10 * time.Second}},
		},
	}
}

// Work processes a notify job: fetches the release, resolves subscriptions,
// sends notifications to all matching channels, and checks agent rules to
// auto-trigger agent runs when version criteria are met.
func (w *NotifyWorker) Work(ctx context.Context, job *river.Job[queue.NotifyJobArgs]) error {
	release, err := w.store.GetRelease(ctx, job.Args.ReleaseID)
	if err != nil {
		return fmt.Errorf("get release: %w", err)
	}

	subs, err := w.store.ListSourceSubscriptions(ctx, job.Args.SourceID)
	if err != nil {
		return fmt.Errorf("list subscriptions: %w", err)
	}

	for _, sub := range subs {
		ch, err := w.store.GetChannel(ctx, sub.ChannelID)
		if err != nil {
			slog.Error("get channel failed", "channel_id", sub.ChannelID, "err", err)
			continue
		}

		sender, ok := w.senders[ch.Type]
		if !ok {
			slog.Warn("unknown channel type", "type", ch.Type)
			continue
		}

		msg := Notification{
			Title:   fmt.Sprintf("New release: %s", release.Version),
			Body:    string(release.RawData),
			Version: release.Version,
		}

		if err := sender.Send(ctx, ch, msg); err != nil {
			slog.Error("send notification failed", "channel", ch.Name, "err", err)
		}
	}

	// Check agent rules and auto-trigger if criteria are met.
	w.checkAgentRules(ctx, release, job.Args.SourceID)

	return nil
}

// checkAgentRules evaluates the project's agent rules against the new release
// and the previous release for this source. If any rule matches, an agent run
// is enqueued. Errors are logged but do not fail the job — notification delivery
// is the primary responsibility.
func (w *NotifyWorker) checkAgentRules(ctx context.Context, release *models.Release, sourceID string) {
	source, err := w.store.GetSource(ctx, sourceID)
	if err != nil {
		slog.Error("get source for agent rules", "source_id", sourceID, "err", err)
		return
	}

	project, err := w.store.GetProject(ctx, source.ProjectID)
	if err != nil {
		slog.Error("get project for agent rules", "project_id", source.ProjectID, "err", err)
		return
	}

	// Parse the project's agent_rules JSON.
	var rules models.AgentRules
	if len(project.AgentRules) > 0 {
		if err := json.Unmarshal(project.AgentRules, &rules); err != nil {
			slog.Error("unmarshal agent rules", "project_id", project.ID, "err", err)
			return
		}
	}

	// Determine the previous version for comparison.
	var previousVersion string
	prev, err := w.store.GetPreviousRelease(ctx, sourceID, release.Version)
	if err != nil {
		slog.Error("get previous release for agent rules", "source_id", sourceID, "err", err)
		return
	}
	if prev != nil {
		previousVersion = prev.Version
	}

	if CheckAgentRules(&rules, release.Version, previousVersion) {
		trigger := fmt.Sprintf("auto:version:%s", release.Version)
		if err := w.store.EnqueueAgentRun(ctx, source.ProjectID, trigger); err != nil {
			slog.Error("enqueue agent run", "project_id", source.ProjectID, "err", err)
		} else {
			slog.Info("agent run triggered by version rules",
				"project_id", source.ProjectID,
				"version", release.Version,
				"previous_version", previousVersion,
			)
		}
	}
}

