   143→	var content *genai.Content
   144→	var err error
   145→	if agentInputSchema != nil {
   146→		if err = utils.ValidateMapOnSchema(margs, agentInputSchema, true); err != nil {
   147→			return nil, fmt.Errorf("argument validation failed for agent %s: %w", t.agent.Name(), err)
   148→		}
   149→		jsonData, err := json.Marshal(margs)
   150→		if err != nil {
   151→			return nil, fmt.Errorf("error serializing tool arguments for agent %s: %w", t.agent.Name(), err)
   152→		}
   153→		content = genai.NewContentFromText(string(jsonData), genai.RoleUser)
   154→	} else {
   155→		input, ok := margs["request"]
   156→		if !ok {
   157→			return nil, fmt.Errorf("missing required argument 'request' for agent %s", t.agent.Name())
   158→		}
   159→		inputText, ok := input.(string)
   160→		if !ok {
   161→			// Try to convert to string if not already one
   162→			inputText = fmt.Sprint(input)
   163→		}
   164→		content = genai.NewContentFromText(inputText, genai.RoleUser)
   165→	}
   166→
   167→	sessionService := session.InMemoryService()
   168→
   169→	r, err := runner.New(runner.Config{
   170→		AppName:        t.agent.Name(),
   171→		Agent:          t.agent,
   172→		SessionService: sessionService,
   173→		// TODO - use forwarding_artifact_service as in python.
   174→		ArtifactService: artifact.InMemoryService(),
   175→		MemoryService:   memory.InMemoryService(),
   176→	})
   177→	if err != nil {
   178→		return nil, fmt.Errorf("failed to create runner")
   179→	}
   180→
   181→	stateMap := make(map[string]any)
   182→
   183→	for k, v := range toolCtx.State().All() {
   184→		// Filter out adk internal states.
   185→		if !strings.HasPrefix(k, "_adk") {
   186→			stateMap[k] = v
   187→		}
   188→	}
   189→
   190→	subSession, err := sessionService.Create(toolCtx, &session.CreateRequest{
   191→		AppName: t.agent.Name(),
   192→		UserID:  toolCtx.UserID(),
   193→		State:   stateMap,
   194→	})
   195→	if err != nil {
   196→		return nil, fmt.Errorf("failed to create session for sub-agent %s: %w", t.agent.Name(), err)
   197→	}
   198→
   199→	// TODO(dpasiukevich): verify agent loop termination.
   200→	eventCh := r.Run(toolCtx, subSession.Session.UserID(), subSession.Session.ID(), content, agent.RunConfig{
   201→		StreamingMode: agent.StreamingModeSSE,
   202→	})
   203→
   204→	var lastEvent *session.Event
   205→	for event, err := range eventCh {
   206→		if err != nil {
   207→			return nil, fmt.Errorf("error during execution of sub-agent %s: %w", t.agent.Name(), err)
   208→		}
   209→		if event.ErrorCode != "" || event.ErrorMessage != "" {
   210→			return nil, fmt.Errorf("error from sub-agent %q (code: %q, message: %q)", t.agent.Name(), event.ErrorCode, event.ErrorMessage)
   211→		}
   212→		if event.LLMResponse.Content != nil {
   213→			lastEvent = event
   214→		}
   215→	}
   216→
   217→	if lastEvent == nil {
   218→		return map[string]any{}, nil
   219→	}
   220→
   221→	lastContent := lastEvent.LLMResponse.Content
   222→	var textParts []string
   223→	for _, part := range lastContent.Parts {
   224→		if part != nil && part.Text != "" {
   225→			textParts = append(textParts, part.Text)
   226→		}
   227→	}
   228→	outputText := strings.Join(textParts, "\n")
   229→
   230→	if outputText == "" {
   231→		return map[string]any{}, nil
   232→	}
   233→	if isLllmAgent {
   234→		internalLlmAgent, ok := t.agent.(llminternal.Agent)
   235→		if !ok {
   236→			return nil, fmt.Errorf("internal error: failed to convert to llm agent")
   237→		}
   238→		if agentOutputSchema := llminternal.Reveal(internalLlmAgent).OutputSchema; agentOutputSchema != nil {
   239→			// Assuming schemautils.ValidateOutputSchema parses the JSON string outputText
   240→			// and validates it against the agentOutputSchema, returning a map[string]any.
   241→			parsedOutput, err := utils.ValidateOutputSchema(outputText, agentOutputSchema)
   242→			if err != nil {
   243→				return nil, fmt.Errorf("output validation failed for sub-agent %s: %w", t.agent.Name(), err)
   244→			}
   245→			return parsedOutput, nil
   246→		}
   247→	}
   248→
   249→	return map[string]any{"result": outputText}, nil
   250→}
