   252→// ProcessRequest adds the agent tool's function declaration to the LLM request.
   253→func (t *agentTool) ProcessRequest(ctx tool.Context, req *model.LLMRequest) error {
   254→	// TODO extract this function somewhere else, simillar operations are done for
   255→	// other tools with function declaration.
   256→	if req.Tools == nil {
   257→		req.Tools = make(map[string]any)
   258→	}
   259→
   260→	name := t.Name()
   261→	if _, ok := req.Tools[name]; ok {
   262→		return fmt.Errorf("duplicate tool: %q", name)
   263→	}
   264→	req.Tools[name] = t
   265→
   266→	if req.Config == nil {
   267→		req.Config = &genai.GenerateContentConfig{}
   268→	}
   269→	if decl := t.Declaration(); decl == nil {
   270→		return nil
   271→	}
   272→	var funcTool *genai.Tool
   273→	for _, tool := range req.Config.Tools {
   274→		if tool != nil && tool.FunctionDeclarations != nil {
   275→			funcTool = tool
   276→			break
   277→		}
   278→	}
   279→	if funcTool == nil {
   280→		req.Config.Tools = append(req.Config.Tools, &genai.Tool{
   281→			FunctionDeclarations: []*genai.FunctionDeclaration{t.Declaration()},
   282→		})
   283→	} else {
   284→		funcTool.FunctionDeclarations = append(funcTool.FunctionDeclarations, t.Declaration())
   285→	}
   286→	return nil
   287→}
