   681→// GetPreviousRelease returns the most recent release for a source that is not
   682→// the given version, ordered by created_at descending. Returns nil (no error)
   683→// if no previous release exists.
   684→func (s *PgStore) GetPreviousRelease(ctx context.Context, sourceID string, beforeVersion string) (*models.Release, error) {
   685→	var rel models.Release
   686→	err := s.pool.QueryRow(ctx,
