   690→		 ORDER BY COALESCE(released_at, created_at) DESC
   691→		 LIMIT 1`, sourceID, beforeVersion,
   692→	).Scan(&rel.ID, &rel.SourceID, &rel.Version, &rel.RawData, &rel.ReleasedAt, &rel.CreatedAt)
   693→	if err != nil {
