   737→// UpdateAgentRunStatus sets the status of an agent run and updates the
   738→// started_at timestamp when transitioning to "running".
   739→func (s *PgStore) UpdateAgentRunStatus(ctx context.Context, id, status string) error {
   740→	var query string
   741→	switch status {
   742→	case "running":
   743→		query = `UPDATE agent_runs SET status = $1, started_at = NOW() WHERE id = $2`
   744→	case "completed":
   745→		query = `UPDATE agent_runs SET status = $1, completed_at = NOW() WHERE id = $2`
   746→	default:
   747→		query = `UPDATE agent_runs SET status = $1 WHERE id = $2`
   748→	}
   749→	tag, err := s.pool.Exec(ctx, query, status, id)
   750→	if err != nil {
   751→		return fmt.Errorf("update agent run status: %w", err)
   752→	}
   753→	if tag.RowsAffected() == 0 {
   754→		return fmt.Errorf("agent run not found: %s", id)
   755→	}
   756→	return nil
   757→}
