   759→// CreateSemanticRelease inserts a semantic release and its source release links
   760→// in a single transaction. The sr.ID field is populated on success.
   761→func (s *PgStore) CreateSemanticRelease(ctx context.Context, sr *models.SemanticRelease, releaseIDs []string) error {
   762→	tx, err := s.pool.Begin(ctx)
   763→	if err != nil {
   764→		return fmt.Errorf("begin tx: %w", err)
   765→	}
   766→	defer tx.Rollback(ctx)
   767→
   768→	err = tx.QueryRow(ctx,
   769→		`INSERT INTO semantic_releases (project_id, version, report, status, completed_at)
   770→		 VALUES ($1, $2, $3, $4, $5)
   771→		 RETURNING id, created_at`,
   772→		sr.ProjectID, sr.Version, sr.Report, sr.Status, sr.CompletedAt,
   773→	).Scan(&sr.ID, &sr.CreatedAt)
   774→	if err != nil {
   775→		return fmt.Errorf("insert semantic release: %w", err)
   776→	}
   777→
   778→	for _, relID := range releaseIDs {
   779→		_, err = tx.Exec(ctx,
   780→			`INSERT INTO semantic_release_sources (semantic_release_id, release_id)
   781→			 VALUES ($1, $2) ON CONFLICT DO NOTHING`,
   782→			sr.ID, relID,
   783→		)
   784→		if err != nil {
   785→			return fmt.Errorf("insert semantic release source: %w", err)
   786→		}
   787→	}
   788→
   789→	return tx.Commit(ctx)
   790→}
