   866→	if err := s.pool.QueryRow(ctx, `SELECT COUNT(*) FROM releases WHERE COALESCE(released_at, created_at) >= NOW() - INTERVAL '7 days'`).Scan(&stats.ReleasesThisWeek); err != nil {
