   179→	// method does not panic and the store state is accessed.
   180→	orch.sendProjectNotifications(context.Background(), run, result)
   181→
   182→	// Verify ListProjectSubscriptions was called (implicitly — if it returned
   183→	// subscriptions, GetChannel must have been called for the channel).
   184→	// The send itself will fail because there's no HTTP server, but that's
   185→	// expected and logged. The key assertion is that the method completes
   186→	// without error and accesses the store correctly.
   187→}
