The `SemanticReport` struct now has new SRE fields (subject, risk_level, etc.) alongside the old fields (summary, availability, etc.). The `parseReport` function in `internal/agent/orchestrator.go` currently requires `report.Summary != ""` as validation. We need to update it to accept either `subject` (new format) or `summary` (old format).

## Your Task: Update parseReport for backward compatibility

### Step 1: Read current state

Read `internal/agent/orchestrator.go` to find the `parseReport` function.

### Step 2: Write tests

Add to `internal/agent/orchestrator_test.go`:

```go
func TestParseReport_NewFormat(t *testing.T) {
	input := `{
		"subject": "🚀 Ready to Deploy: Geth v1.10.15",
		"risk_level": "CRITICAL",
		"risk_reason": "Hard Fork detected",
		"status_checks": ["Docker Image Verified"],
		"changelog_summary": "Fixes sync bug",
		"availability": "GA",
		"adoption": "12% updated",
		"urgency": "Critical",
		"recommendation": "Wait for 25% adoption.",
		"download_commands": ["docker pull ethereum/client-go:v1.10.15"],
		"download_links": ["https://example.com/release"]
	}`

	report, err := parseReport(input)
	if err != nil {
		t.Fatalf("parseReport: %v", err)
	}
	if report.Subject != "🚀 Ready to Deploy: Geth v1.10.15" {
		t.Errorf("subject: got %q", report.Subject)
	}
	if report.RiskLevel != "CRITICAL" {
		t.Errorf("risk_level: got %q", report.RiskLevel)
	}
	if len(report.StatusChecks) != 1 {
		t.Errorf("status_checks: got %d", len(report.StatusChecks))
	}
}

func TestParseReport_OldFormat(t *testing.T) {
	input := `{
		"summary": "Major changes across releases",
		"availability": "GA",
		"adoption": "Immediate",
		"urgency": "High",
		"recommendation": "Upgrade now"
	}`

	report, err := parseReport(input)
	if err != nil {
		t.Fatalf("parseReport: %v", err)
	}
	if report.Summary != "Major changes across releases" {
		t.Errorf("summary: got %q", report.Summary)
	}
}

func TestParseReport_NoSubjectOrSummary(t *testing.T) {
	input := `{
		"availability": "GA",
		"urgency": "Low"
	}`

	_, err := parseReport(input)
	if err == nil {
		t.Fatal("expected error for missing subject and summary")
	}
}
```

### Step 3: Update parseReport validation

In the `parseReport` function, change the validation from:
```go
if report.Summary == "" {
    return nil, fmt.Errorf("report is missing required 'summary' field")
}
```
To:
```go
if report.Subject == "" && report.Summary == "" {
    return nil, fmt.Errorf("report is missing required 'subject' or 'summary' field")
}
```

### Step 4: Run tests

Run: `go test ./internal/agent/ -run TestParseReport -v`

