   703→// EnqueueAgentRun creates an agent_run row and enqueues a River AgentJobArgs.
   704→// This follows the transactional outbox pattern for zero-loss guarantee.
   705→func (s *PgStore) EnqueueAgentRun(ctx context.Context, projectID, trigger, version string) error {
   706→	tx, err := s.pool.Begin(ctx)
   707→	if err != nil {
   708→		return fmt.Errorf("begin tx: %w", err)
   709→	}
   710→	defer tx.Rollback(ctx)
   711→
   712→	var runID string
   713→	err = tx.QueryRow(ctx,
   714→		`INSERT INTO agent_runs (project_id, trigger, version, status)
   715→		 VALUES ($1, $2, $3, 'pending')
   716→		 RETURNING id`, projectID, trigger, version,
   717→	).Scan(&runID)
   718→	if err != nil {
   719→		return fmt.Errorf("insert agent run: %w", err)
   720→	}
   721→
   722→	if s.river != nil {
   723→		_, err = s.river.InsertTx(ctx, tx, queue.AgentJobArgs{
   724→			AgentRunID: runID,
   725→			ProjectID:  projectID,
   726→			Version:    version,
   727→		}, nil)
   728→		if err != nil {
   729→			return fmt.Errorf("enqueue agent job: %w", err)
   730→		}
   731→	}
   732→
   733→	return tx.Commit(ctx)
   734→}
