   738→// UpdateAgentRunStatus sets the status of an agent run and updates the
   739→// started_at timestamp when transitioning to "running".
   740→func (s *PgStore) UpdateAgentRunStatus(ctx context.Context, id, status string) error {
   741→	var query string
   742→	switch status {
   743→	case "running":
   744→		query = `UPDATE agent_runs SET status = $1, started_at = NOW() WHERE id = $2`
   745→	case "completed":
   746→		query = `UPDATE agent_runs SET status = $1, completed_at = NOW() WHERE id = $2`
   747→	default:
   748→		query = `UPDATE agent_runs SET status = $1 WHERE id = $2`
   749→	}
   750→	tag, err := s.pool.Exec(ctx, query, status, id)
   751→	if err != nil {
   752→		return fmt.Errorf("update agent run status: %w", err)
   753→	}
   754→	if tag.RowsAffected() == 0 {
   755→		return fmt.Errorf("agent run not found: %s", id)
   756→	}
   757→	return nil
   758→}
