   760→// CreateSemanticRelease inserts a semantic release and its source release links
   761→// in a single transaction. The sr.ID field is populated on success.
   762→func (s *PgStore) CreateSemanticRelease(ctx context.Context, sr *models.SemanticRelease, releaseIDs []string) error {
   763→	tx, err := s.pool.Begin(ctx)
   764→	if err != nil {
   765→		return fmt.Errorf("begin tx: %w", err)
   766→	}
   767→	defer tx.Rollback(ctx)
   768→
   769→	err = tx.QueryRow(ctx,
   770→		`INSERT INTO semantic_releases (project_id, version, report, status, completed_at)
   771→		 VALUES ($1, $2, $3, $4, $5)
   772→		 RETURNING id, created_at`,
   773→		sr.ProjectID, sr.Version, sr.Report, sr.Status, sr.CompletedAt,
   774→	).Scan(&sr.ID, &sr.CreatedAt)
   775→	if err != nil {
   776→		return fmt.Errorf("insert semantic release: %w", err)
   777→	}
   778→
   779→	for _, relID := range releaseIDs {
   780→		_, err = tx.Exec(ctx,
   781→			`INSERT INTO semantic_release_sources (semantic_release_id, release_id)
   782→			 VALUES ($1, $2) ON CONFLICT DO NOTHING`,
   783→			sr.ID, relID,
   784→		)
   785→		if err != nil {
   786→			return fmt.Errorf("insert semantic release source: %w", err)
   787→		}
   788→	}
   789→
   790→	return tx.Commit(ctx)
   791→}
